using Standard;namespace BgControls.Windows.Controls;/// <summary>/// 应用程序辅助类，提供关于环境、视觉树及 DPI 转换的工具方法./// </summary>internal class ApplicationHelper{    /// <summary>    /// Gets a value indicating whether 程序是否具有完全信任权限.    /// </summary>    public static bool IsFullTrust { get; private set; }    /// <summary>    /// Gets 应用程序的当前大小.    /// </summary>    internal static Size ApplicationSize    {        get        {            // 如果是浏览器承载模式，则获取主窗口内容的大小.            if (BrowserInteropHelper.IsBrowserHosted)            {                FrameworkElement? content = (Application.Current.MainWindow.Content as FrameworkElement) ?? Application.Current.MainWindow;                return new Size(content.ActualWidth, content.ActualHeight);            }            // 否则返回虚拟屏幕的全尺寸.            return new Size(SystemParameters.VirtualScreenWidth, SystemParameters.VirtualScreenHeight);        }    }    /// <summary>    /// Gets 应用程序的当前位置坐标.    /// </summary>    internal static Point ApplicationLocation    {        get        {            if (BrowserInteropHelper.IsBrowserHosted)            {                return default(Point);            }            return new Point(SystemParameters.VirtualScreenLeft, SystemParameters.VirtualScreenTop);        }    }    /// <summary>    /// Gets 当前处于激活状态或主窗口的根视觉元素.    /// </summary>    internal static FrameworkElement? RootVisual    {        get        {            if (Application.Current == null)            {                return null;            }            // 确保在 UI 线程访问窗口集合.            if (Application.Current.Dispatcher.CheckAccess())            {                return Application.Current.Windows.Cast<Window>().FirstOrDefault(w => w.IsActive) ?? Application.Current.MainWindow;            }            return null;        }    }    /// <summary>    /// Gets a value indicating whether 当前操作系统是否为 Windows 8.    /// </summary>    internal static bool IsWindows8    {        get        {            int majorVersion = Environment.OSVersion.Version.Major;            int minorVersion = Environment.OSVersion.Version.Minor;            if (majorVersion == 6)            {                return minorVersion == 2;            }            return false;        }    }    /// <summary>    /// Gets a value indicating whether 当前操作系统是否为 Windows 8 或更高版本.    /// </summary>    internal static bool IsWindows8OrNewer    {        get        {            Version win8Version = new Version(6, 2, 9200, 0);            if (Environment.OSVersion.Platform == PlatformID.Win32NT)            {                return Environment.OSVersion.Version >= win8Version;            }            return false;        }    }    /// <summary>    /// Initializes a new instance of the <see cref="ApplicationHelper"/> class.    /// </summary>    static ApplicationHelper()    {        // 静态构造函数用于初始化权限状态.        if (typeof(ApplicationHelper).Assembly.IsFullyTrusted)        {            ApplicationHelper.CheckForUnmanagedPermissions();        }    }    /// <summary>    /// 获取指定元素的所有父级节点序列.    /// </summary>    /// <param name="element">目标对象.</param>    /// <returns>从当前对象开始向上的父级迭代序列.</returns>    internal static IEnumerable<DependencyObject> GetParents(DependencyObject? element)    {        DependencyObject? current = element;        while (current != null)        {            DependencyObject? parent = VisualTreeHelper.GetParent(current);            // 如果视觉树父级为空，尝试通过 FrameworkElement 获取逻辑树父级.            if (parent == null && current is FrameworkElement frameworkElement)            {                parent = frameworkElement.Parent;            }            yield return current;            current = parent;        }    }    /// <summary>    /// 向上查找并返回指定元素的根视觉元素.    /// </summary>    /// <param name="element">起始元素.</param>    /// <returns>根级 FrameworkElement.</returns>    internal static FrameworkElement? GetRootVisual(DependencyObject? element)    {        if (element == null)        {            return ApplicationHelper.RootVisual;        }        DependencyObject? root = null;        DependencyObject? current = element;        while (current != null)        {            DependencyObject? parent = VisualTreeHelper.GetParent(current);            if (parent == null && current is FrameworkElement frameworkElement)            {                parent = frameworkElement.Parent;                if (parent == null)                {                    root = current;                    break;                }            }            current = parent;        }        return root as FrameworkElement;    }    /// <summary>    /// 获取第一个逻辑根元素，搜索时会停止于 Popup 节点.    /// </summary>    /// <param name="element">起始元素.</param>    /// <returns>逻辑根级 FrameworkElement.</returns>    internal static FrameworkElement? GetFirstLogicalRoot(DependencyObject? element)    {        if (element == null)        {            return ApplicationHelper.RootVisual;        }        DependencyObject? root = null;        DependencyObject? current = element;        while (current != null && !(current is Popup))        {            DependencyObject? parent = VisualTreeHelper.GetParent(current);            if (parent == null && current is FrameworkElement frameworkElement)            {                parent = frameworkElement.Parent;                if (parent == null)                {                    root = current;                    break;                }            }            current = parent;        }        return root as FrameworkElement;    }    /// <summary>    /// 获取指定视觉元素位置在屏幕上的 DPI 感知坐标.    /// </summary>    /// <param name="visual">视觉对象.</param>    /// <param name="positionInVisual">对象内部相对坐标.</param>    /// <returns>转换后的屏幕坐标.</returns>    internal static Point GetDpiAwarePositionOnScreen(UIElement visual, Point positionInVisual)    {        ArgumentNullException.ThrowIfNull(visual, nameof(visual));        GeneralTransform transform = ApplicationHelper.TransformToScreenRoot(visual);        return transform.Transform(positionInVisual);    }    /// <summary>    /// 构建从目标元素到屏幕根节点的坐标变换.    /// </summary>    /// <param name="target">目标 UI 元素.</param>    /// <returns>几何变换对象.</returns>    internal static GeneralTransform TransformToScreenRoot(UIElement target)    {        ArgumentNullException.ThrowIfNull(target, nameof(target));        // 如果元素未加载，无法进行准确的坐标转换.        if (target is FrameworkElement fe && !fe.IsLoaded)        {            return Transform.Identity;        }        if (BrowserInteropHelper.IsBrowserHosted)        {            return target.TransformToAncestor(ApplicationHelper.GetRootVisual(target));        }        Visual? rootVisual = Window.GetWindow(target);        if (rootVisual == null)        {            rootVisual = target.ParentOfType<Window>();        }        if (rootVisual != null)        {            PresentationSource? source = null;            // 处理不在同一视觉树分支下的情况（如某些弹出层）.            if (!rootVisual.IsAncestorOf(target))            {                source = PresentationSource.FromVisual(target);                if (source != null)                {                    rootVisual = source.RootVisual;                }            }            Transform? relativeTransform = target.TransformToAncestor(rootVisual) as Transform;            double scaleFactor = DpiHelper.GetPerMonitorDPIAwareScaleFactor(rootVisual);            // 将屏幕原点坐标转换为逻辑坐标.            Point screenOrigin = DpiHelper.ScaledDevicePixelsToLogical(rootVisual.PointToScreen(new Point(0.0, 0.0)), scaleFactor);            TransformGroup group = new TransformGroup();            if (relativeTransform != null)            {                group.Children.Add(relativeTransform);            }            group.Children.Add(new TranslateTransform { X = screenOrigin.X, Y = screenOrigin.Y });            return group;        }        // 尝试从附加属性提供的适配器中查找定位信息.        Visual? adapterVisual = ApplicationHelper.GetParents(target)            .OfType<Visual>()            .FirstOrDefault(v => v.ReadLocalValue(WindowInteropabilityHelper.WindowInteropabilityAdapterProperty) != DependencyProperty.UnsetValue);        if (adapterVisual != null)        {            IWindowInteropabilityAdapter adapter = WindowInteropabilityHelper.GetWindowInteropabilityAdapter(adapterVisual);            Transform? adapterTransform = target.TransformToAncestor(adapterVisual) as Transform;            TransformGroup adapterGroup = new TransformGroup();            if (adapterTransform != null)            {                adapterGroup.Children.Add(adapterTransform);            }            adapterGroup.Children.Add(new TranslateTransform { X = adapter.AbsoluteLeft, Y = adapter.AbsoluteTop });            return adapterGroup;        }        return target.TransformToAncestor(ApplicationHelper.GetRootVisual(target));    }    /// <summary>    /// 获取指定窗口的屏幕位置.    /// </summary>    /// <param name="window">目标窗口.</param>    /// <returns>窗口在屏幕上的左上角坐标.</returns>    public static Point GetWindowPosition(Window window)    {        ArgumentNullException.ThrowIfNull(window, nameof(window));        // 如果窗口最大化，通过监视器信息获取工作区位置.        if (window.WindowState == WindowState.Maximized)        {            IntPtr windowHandle = new WindowInteropHelper(window).Handle;            const uint monitorNearest = 2;            IntPtr monitorHandle = NativeMethods.MonitorFromWindow(windowHandle, monitorNearest);            if (monitorHandle != IntPtr.Zero)            {                MONITORINFO info = new MONITORINFO();                NativeMethods.GetMonitorInfo(monitorHandle, out info);                RECT monitorRect = info.rcMonitor;                return NativeMethods.ConvertFromRECT(monitorRect).TopLeft;            }            return default(Point);        }        return new Point(window.Left, window.Top);    }    /// <summary>    /// 检查并设置非托管代码访问权限状态.    /// </summary>    private static void CheckForUnmanagedPermissions()    {        if (typeof(ApplicationHelper).Assembly.IsFullyTrusted)        {            PermissionSet permissions = new PermissionSet(PermissionState.None);            permissions.AddPermission(new SecurityPermission(SecurityPermissionFlag.UnmanagedCode));            ApplicationHelper.IsFullTrust = permissions.IsSubsetOf(AppDomain.CurrentDomain.PermissionSet);        }    }}